        : (
          <div style={{overflowX:"auto", background:"#1e293b", borderRadius:12, border:"1px solid #334155"}}>
            <table style={{width:"100%", borderCollapse:"collapse"}}>
              <thead>
                <tr><th style={TH}>Medicine</th><th style={TH}>Category</th><th style={TH}>Current Stock</th><th style={TH}>Min Stock</th><th style={TH}>Status</th></tr>
